def safe_divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return "Cannot divide by zero"
    except TypeError:
        return "Both values must be numbers"

print(safe_divide(10, 2))
print(safe_divide(10, 0))
print(safe_divide(10, "two"))

def read_marks(raw):
    try:
        value = int(raw)
    except ValueError:
        print(repr(raw), "is not a number")
    else:
        print("Recorded mark:", value)
    finally:
        print("-- entry processed --")

read_marks("92")
read_marks("ninety two")

values = ["10", "abc", "25"]

for raw in values:
    try:
        print(int(raw) * 2)
    except ValueError as e:
        print("Skipped one:", e)

def set_age(age):
    if age < 0 or age > 130:
        raise ValueError("age must be between 0 and 130, got " + str(age))
    print("Age set to", age)

set_age(12)

try:
    set_age(-5)
except ValueError as e:
    print("Rejected:", e)

class InsufficientFunds(Exception):
    pass

class Wallet:
    def __init__(self, balance):
        self.balance = balance

    def spend(self, amount):
        if amount > self.balance:
            raise InsufficientFunds("tried to spend " + str(amount) + ", have " + str(self.balance))
        self.balance = self.balance - amount
        return self.balance

w = Wallet(100)
print("Left:", w.spend(60))

try:
    w.spend(500)
except InsufficientFunds as e:
    print("Blocked:", e)
